mapper.select:
select id, store_no, goods_no, goods_price, goods_stock, goods_type, create_time, update_time
from goods_store
where store_no=#{storeNo} and goods_no=#{goodsNo}

select gs.id,gs.store_no,gs.goods_no,gs.goods_price,gs.goods_stock,gs.goods_type,gs.create_time,gs.update_time, g.id gid, g.goods_no ggoods_no, g.goods_name, g.category_id, g.goods_introduce, g.goods_content, g.goods_state,g.goods_picture, g.goods_market_price, g.create_time gcreate_time, g.update_time gupdate_time from goods_store gs inner join goods g on gs.goods_no=g.goods_no where store_no=#{storeNo}
and g.goods_name like concat('%',#{goodsName},'%')
and g.goods_content=#{goodsContent}
order by gs.create_time desc
